import{_ as e,o as a,c as n,a4 as t}from"./chunks/framework.Q2e_3lsv.js";const u=JSON.parse('{"title":"LLM Integration with cljam-mcp","description":"","frontmatter":{},"headers":[],"relativePath":"guide/mcp.md","filePath":"guide/mcp.md"}'),i={name:"guide/mcp.md"};function o(p,s,l,d,c,r){return a(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="llm-integration-with-cljam-mcp" tabindex="-1">LLM Integration with cljam-mcp <a class="header-anchor" href="#llm-integration-with-cljam-mcp" aria-label="Permalink to &quot;LLM Integration with cljam-mcp&quot;">​</a></h1><p><code>@regibyte/cljam-mcp</code> is an <a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">MCP</a> server that gives LLMs a persistent, stateful Clojure REPL as tool calls. Sessions survive across turns — define a function, call it ten turns later.</p><h2 id="setup-in-claude-code" tabindex="-1">Setup in Claude Code <a class="header-anchor" href="#setup-in-claude-code" aria-label="Permalink to &quot;Setup in Claude Code&quot;">​</a></h2><p>Add to your project&#39;s <code>.claude.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;cljam&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@regibyte/cljam-mcp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Claude Code restarts the server automatically on crash.</p><h2 id="mode-1-built-in-sessions" tabindex="-1">Mode 1: Built-in sessions <a class="header-anchor" href="#mode-1-built-in-sessions" aria-label="Permalink to &quot;Mode 1: Built-in sessions&quot;">​</a></h2><p>The LLM creates and manages Clojure sessions directly:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>new_session {}</span></span>
<span class="line"><span>→ { session_id: &quot;abc123&quot;, preset: &quot;sandbox&quot; }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>eval { session_id: &quot;abc123&quot;, code: &quot;(defn greet [n] (str \\&quot;hello \\&quot; n))&quot; }</span></span>
<span class="line"><span>eval { session_id: &quot;abc123&quot;, code: &quot;(greet \\&quot;world\\&quot;)&quot; }</span></span>
<span class="line"><span>→ { result: &quot;\\&quot;hello world\\&quot;&quot; }</span></span></code></pre></div><p>Load project files with <code>root_dir</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>new_session { root_dir: &quot;/path/to/project&quot; }</span></span>
<span class="line"><span>load_file { session_id: &quot;...&quot;, path: &quot;src/my/lib.clj&quot; }</span></span>
<span class="line"><span>eval { session_id: &quot;...&quot;, code: &quot;(my.lib/main)&quot; }</span></span></code></pre></div><h2 id="mode-2-nrepl-bridge-pair-programming" tabindex="-1">Mode 2: nREPL bridge (pair programming) <a class="header-anchor" href="#mode-2-nrepl-bridge-pair-programming" aria-label="Permalink to &quot;Mode 2: nREPL bridge (pair programming)&quot;">​</a></h2><p>Connect to the same nREPL server the human developer is using in Calva. Both parties share the same live runtime — atoms, namespaces, definitions:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Human starts the nREPL server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cljam</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nrepl-server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --root-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 7888</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Human connects Calva → Calva: Connect to Running REPL Server in Project</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># LLM connects via MCP</span></span>
<span class="line"><span>connect_nrepl { port: 7888 }</span></span>
<span class="line"><span>→ {</span></span>
<span class="line"><span>    connection_id: &quot;conn-xyz&quot;,</span></span>
<span class="line"><span>    session_id: &quot;my-fresh-session-uuid&quot;,</span></span>
<span class="line"><span>    other_sessions: [</span></span>
<span class="line"><span>      { id: &quot;calva-session-uuid&quot;, ns: &quot;my-app.dev&quot; }</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span></span></span>
<span class="line"><span># LLM evals into Calva&#39;s session — true shared state</span></span>
<span class="line"><span>nrepl_eval {</span></span>
<span class="line"><span>  connection_id: &quot;conn-xyz&quot;,</span></span>
<span class="line"><span>  session_id: &quot;calva-session-uuid&quot;,</span></span>
<span class="line"><span>  code: &quot;(def answer 42)&quot;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span># Human can now call (answer) from Calva and get 42</span></span></code></pre></div><p><code>other_sessions</code> in the connect response identifies every pre-existing session. Pick the one with the active namespace — that&#39;s Calva.</p><h2 id="introspection-with-describe" tabindex="-1">Introspection with <code>describe</code> <a class="header-anchor" href="#introspection-with-describe" aria-label="Permalink to &quot;Introspection with \`describe\`&quot;">​</a></h2><p><code>describe</code> is a Clojure function, called inside <code>eval</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eval { session_id: &quot;...&quot;, code: &quot;(describe #&#39;clojure.core/map)&quot; }</span></span>
<span class="line"><span>→ { :name map :ns clojure.core :doc &quot;...&quot; :arglists (...) }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>eval { session_id: &quot;...&quot;, code: &quot;(describe (find-ns &#39;clojure.core))&quot; }</span></span>
<span class="line"><span>→ { :name clojure.core :vars [...] }</span></span></code></pre></div><h2 id="quick-reference-with-handbook" tabindex="-1">Quick reference with <code>handbook</code> <a class="header-anchor" href="#quick-reference-with-handbook" aria-label="Permalink to &quot;Quick reference with \`handbook\`&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>handbook {}</span></span>
<span class="line"><span>→ list of all topic keys</span></span>
<span class="line"><span></span></span>
<span class="line"><span>handbook { topic: &quot;sort&quot; }</span></span>
<span class="line"><span>→ dense reference entry with examples</span></span></code></pre></div><p>Handbook topics include <code>jvm-gaps</code>, <code>types</code>, <code>records</code>, <code>protocols</code>, <code>schema-api</code>, <code>describe</code>, <code>sessions</code>, <code>pair-programming</code>, and more.</p><h2 id="all-tools" tabindex="-1">All tools <a class="header-anchor" href="#all-tools" aria-label="Permalink to &quot;All tools&quot;">​</a></h2><h3 id="mode-1" tabindex="-1">Mode 1 <a class="header-anchor" href="#mode-1" aria-label="Permalink to &quot;Mode 1&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th></tr></thead><tbody><tr><td><code>new_session</code></td><td>Create a session (<code>sandbox</code> or <code>node</code> preset, optional <code>root_dir</code>)</td></tr><tr><td><code>eval</code></td><td>Evaluate Clojure — returns <code>result</code>, <code>ns</code>, <code>stdout</code>, <code>error</code></td></tr><tr><td><code>load_file</code></td><td>Load a <code>.clj</code> file into the session</td></tr><tr><td><code>list_sessions</code></td><td>List active sessions</td></tr><tr><td><code>delete_session</code></td><td>Delete a session</td></tr><tr><td><code>handbook</code></td><td>Look up a quick-reference topic</td></tr></tbody></table><h3 id="mode-2" tabindex="-1">Mode 2 <a class="header-anchor" href="#mode-2" aria-label="Permalink to &quot;Mode 2&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th></tr></thead><tbody><tr><td><code>connect_nrepl</code></td><td>Connect to nREPL server — returns <code>connection_id</code>, <code>session_id</code>, <code>other_sessions</code></td></tr><tr><td><code>nrepl_eval</code></td><td>Eval in an nREPL session</td></tr><tr><td><code>nrepl_sessions</code></td><td>List sessions on this connection</td></tr><tr><td><code>nrepl_new_session</code></td><td>Clone a fresh session</td></tr><tr><td><code>nrepl_server_sessions</code></td><td>List ALL sessions server-wide (all connected clients)</td></tr><tr><td><code>nrepl_close</code></td><td>Close the connection</td></tr></tbody></table>`,27)])])}const k=e(i,[["render",o]]);export{u as __pageData,k as default};
